module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const url = esc((args.url || '').trim());
const body = (content || '').trim();
const theme = (args.theme || 'light').toLowerCase() === 'dark' ? 'dark' : 'light';
const shadow = !(args.shadow === false || args.shadow === 'false');
const radius = (() => { const n = parseFloat(args.radius); return Number.isFinite(n) && n >= 0 ? n : 10; })();
const mw = parseFloat(args.maxwidth);
let style = `--br-r:${radius}px;`;
if (Number.isFinite(mw) && mw > 0) style += ` max-width:${mw}px; margin-left:auto; margin-right:auto;`;
const cls = `mdp-mod-browser mdp-br-${theme}${shadow ? '' : ' mdp-br-noshadow'}`;
return `\n\n<div class="${cls}" style="${style}"><div class="mdp-br-bar"><span class="mdp-br-dot"></span><span class="mdp-br-dot"></span><span class="mdp-br-dot"></span><span class="mdp-br-url">${url}</span></div><div class="mdp-br-body">\n\n${body}\n\n</div></div>\n\n`;
